class Solution {
public:
    int minSwaps(vector<int>& nums) {
        int n = nums.size();
        int totalOnes = 0;
        for (int num : nums) {
            totalOnes += num;
        }
        int minSwaps = n;
        int onesInWindow = 0;
        for (int i = 0; i < totalOnes; ++i) {
            onesInWindow += nums[i];
        }
        minSwaps = min(minSwaps, totalOnes - onesInWindow);
        for (int i = totalOnes; i < n + totalOnes; ++i) {
            onesInWindow += nums[i % n];
            onesInWindow -= nums[(i - totalOnes) % n];
            minSwaps = min(minSwaps, totalOnes - onesInWindow);
        }
        return minSwaps;
    }
};
